class Dog {
  String name;

  // This is an Instance Method (Behavior)
  void bark() {
    // It can freely access its own internal attributes!
    System.out.println(name + " says WOOF!");
  }
}

class Main {
  public static void main(String[] args) {
    Dog myDog = new Dog();
    myDog.name = "Rex";

    // Using dot-notation to command the object to act
    myDog.bark();
  }
}
